+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { OrderRepository } from '../../src/repositories/order.repository.js';
+import { UserRepository } from '../../src/repositories/user.repository.js';
+import { AnalyticsService } from '../../src/services/analytics.service.js';
+import {
+  parseAnalyticsQuery,
+  getDashboardHandler,
+  getMetricHandler,
+  getOrderAnalyticsHandler,
+  getUserAnalyticsHandler,
+} from '../../src/routes/analytics.routes.js';
+import type { AnalyticsQueryParams } from '../../src/routes/analytics.routes.js';
+import type { Order } from '../../src/models/order.js';
+import type { User } from '../../src/models/user.js';
+
+// ---------------------------------------------------------------------------
+// Helpers
+// ---------------------------------------------------------------------------
+
+function makeOrder(overrides: Partial<Order> & { id: string }): Order {
+  return {
+    userId: 'user-1',
+    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
+    total: 100,
+    status: 'pending',
+    createdAt: new Date('2025-01-15'),
+    updatedAt: new Date('2025-01-15'),
+    ...overrides,
+  };
+}
+
+function makeUser(overrides: Partial<User> & { id: string }): User {
+  return {
+    name: 'Test User',
+    email: `${overrides.id}@example.com`,
+    role: 'member',
+    createdAt: new Date('2025-01-15'),
+    updatedAt: new Date('2025-01-15'),
+    ...overrides,
+  };
+}
+
+const validParams: AnalyticsQueryParams = {
+  startDate: '2025-01-01',
+  endDate: '2025-01-31',
+  granularity: 'day',
+};
+
+// ---------------------------------------------------------------------------
+// parseAnalyticsQuery
+// ---------------------------------------------------------------------------
+
+describe('parseAnalyticsQuery', () => {
+  it('parses valid params', () => {
+    const query = parseAnalyticsQuery(validParams);
+    expect(query.timeRange.start).toEqual(new Date('2025-01-01'));
+    expect(query.timeRange.end).toEqual(new Date('2025-01-31'));
+    expect(query.granularity).toBe('day');
+  });
+
+  it('defaults granularity to day', () => {
+    const query = parseAnalyticsQuery({ startDate: '2025-01-01', endDate: '2025-01-31' });
+    expect(query.granularity).toBe('day');
+  });
+
+  it('throws on invalid startDate', () => {
+    expect(() => parseAnalyticsQuery({ startDate: 'nope', endDate: '2025-01-31' }))
+      .toThrow('Invalid startDate');
+  });
+
+  it('throws on invalid endDate', () => {
+    expect(() => parseAnalyticsQuery({ startDate: '2025-01-01', endDate: 'nope' }))
+      .toThrow('Invalid endDate');
+  });
+
+  it('throws when startDate >= endDate', () => {
+    expect(() => parseAnalyticsQuery({ startDate: '2025-02-01', endDate: '2025-01-01' }))
+      .toThrow('startDate must be before endDate');
+  });
+
+  it('throws on invalid granularity', () => {
+    expect(() => parseAnalyticsQuery({ startDate: '2025-01-01', endDate: '2025-01-31', granularity: 'quarter' }))
+      .toThrow('Invalid granularity');
+  });
+});
+
+// ---------------------------------------------------------------------------
+// Route handlers
+// ---------------------------------------------------------------------------
+
+describe('analytics route handlers', () => {
+  let db: Database;
+  let orderRepo: OrderRepository;
+  let userRepo: UserRepository;
+  let service: AnalyticsService;
+
+  beforeEach(() => {
+    db = new Database();
+    orderRepo = new OrderRepository(db);
+    userRepo = new UserRepository(db);
+    service = new AnalyticsService(orderRepo, userRepo);
+  });
+
+  // -- getDashboardHandler --------------------------------------------------
+
+  describe('getDashboardHandler', () => {
+    it('returns success with dashboard data', async () => {
+      userRepo.save(makeUser({ id: 'u1' }));
+      orderRepo.save(makeOrder({ id: 'o1' }));
+
+      const result = await getDashboardHandler(service, validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.metrics).toHaveLength(4);
+      expect(result.data.orders.totalOrders).toBe(1);
+      expect(result.data.users.newUsers).toBe(1);
+      expect(result.data.generatedAt).toBeInstanceOf(Date);
+      expect(result.data.timeRange.start).toEqual(new Date('2025-01-01'));
+    });
+
+    it('returns success with empty data', async () => {
+      const result = await getDashboardHandler(service, validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.orders.totalOrders).toBe(0);
+      expect(result.data.users.newUsers).toBe(0);
+    });
+
+    it('returns error on invalid params', async () => {
+      const result = await getDashboardHandler(service, { startDate: 'bad', endDate: '2025-01-31' });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Invalid startDate');
+    });
+  });
+
+  // -- getMetricHandler -----------------------------------------------------
+
+  describe('getMetricHandler', () => {
+    it('returns revenue metric', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', total: 250 }));
+
+      const result = await getMetricHandler(service, 'revenue', validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.type).toBe('revenue');
+      expect(result.data.currentValue).toBe(250);
+    });
+
+    it('returns orders metric', async () => {
+      orderRepo.save(makeOrder({ id: 'o1' }));
+      orderRepo.save(makeOrder({ id: 'o2' }));
+
+      const result = await getMetricHandler(service, 'orders', validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.type).toBe('orders');
+      expect(result.data.currentValue).toBe(2);
+    });
+
+    it('returns users metric', async () => {
+      userRepo.save(makeUser({ id: 'u1' }));
+
+      const result = await getMetricHandler(service, 'users', validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.type).toBe('users');
+      expect(result.data.currentValue).toBe(1);
+    });
+
+    it('returns average-order-value metric', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', total: 100 }));
+      orderRepo.save(makeOrder({ id: 'o2', total: 200 }));
+
+      const result = await getMetricHandler(service, 'average-order-value', validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.type).toBe('average-order-value');
+      expect(result.data.currentValue).toBe(150);
+    });
+
+    it('returns error for invalid metric type', async () => {
+      const result = await getMetricHandler(service, 'invalid-type', validParams);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid metric type');
+      expect(result.error).toContain('invalid-type');
+    });
+
+    it('returns error on invalid params', async () => {
+      const result = await getMetricHandler(service, 'revenue', { startDate: '2025-01-01', endDate: 'bad' });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Invalid endDate');
+    });
+  });
+
+  // -- getOrderAnalyticsHandler ---------------------------------------------
+
+  describe('getOrderAnalyticsHandler', () => {
+    it('returns order analytics with data', async () => {
+      orderRepo.save(makeOrder({ id: 'o1', total: 100, status: 'pending' }));
+      orderRepo.save(makeOrder({ id: 'o2', total: 200, status: 'delivered' }));
+
+      const result = await getOrderAnalyticsHandler(service, validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.totalOrders).toBe(2);
+      expect(result.data.totalRevenue).toBe(300);
+      expect(result.data.averageOrderValue).toBe(150);
+      expect(result.data.statusBreakdown.pending).toBe(1);
+      expect(result.data.statusBreakdown.delivered).toBe(1);
+      expect(result.data.revenueSeries.label).toBe('revenue');
+      expect(result.data.orderCountSeries.label).toBe('orders');
+    });
+
+    it('returns empty order analytics', async () => {
+      const result = await getOrderAnalyticsHandler(service, validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.totalOrders).toBe(0);
+      expect(result.data.totalRevenue).toBe(0);
+    });
+
+    it('returns error on invalid params', async () => {
+      const result = await getOrderAnalyticsHandler(service, { startDate: '2025-02-01', endDate: '2025-01-01' });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('startDate must be before endDate');
+    });
+  });
+
+  // -- getUserAnalyticsHandler ----------------------------------------------
+
+  describe('getUserAnalyticsHandler', () => {
+    it('returns user analytics with data', async () => {
+      userRepo.save(makeUser({ id: 'u1', role: 'admin' }));
+      userRepo.save(makeUser({ id: 'u2', role: 'member' }));
+      userRepo.save(makeUser({ id: 'u3', role: 'member' }));
+
+      const result = await getUserAnalyticsHandler(service, validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.newUsers).toBe(3);
+      expect(result.data.usersByRole).toEqual({ admin: 1, member: 2 });
+      expect(result.data.newUserSeries.label).toBe('newUsers');
+    });
+
+    it('returns empty user analytics', async () => {
+      const result = await getUserAnalyticsHandler(service, validParams);
+
+      expect(result.success).toBe(true);
+      expect(result.data.newUsers).toBe(0);
+    });
+
+    it('returns error on invalid params', async () => {
+      const result = await getUserAnalyticsHandler(service, { startDate: 'bad', endDate: '2025-01-31' });
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Invalid startDate');
+    });
+  });
+
+  // -- Response format consistency ------------------------------------------
+
+  describe('response format', () => {
+    it('all handlers return consistent envelope shape on success', async () => {
+      const dashboard = await getDashboardHandler(service, validParams);
+      const metric = await getMetricHandler(service, 'revenue', validParams);
+      const orders = await getOrderAnalyticsHandler(service, validParams);
+      const users = await getUserAnalyticsHandler(service, validParams);
+
+      for (const response of [dashboard, metric, orders, users]) {
+        expect(response).toHaveProperty('success', true);
+        expect(response).toHaveProperty('data');
+        expect(response.error).toBeUndefined();
+      }
+    });
+
+    it('all handlers return consistent envelope shape on error', async () => {
+      const badParams: AnalyticsQueryParams = { startDate: 'invalid', endDate: '2025-01-31' };
+
+      const dashboard = await getDashboardHandler(service, badParams);
+      const metric = await getMetricHandler(service, 'revenue', badParams);
+      const orders = await getOrderAnalyticsHandler(service, badParams);
+      const users = await getUserAnalyticsHandler(service, badParams);
+
+      for (const response of [dashboard, metric, orders, users]) {
+        expect(response.success).toBe(false);
+        expect(response.error).toBeDefined();
+        expect(typeof response.error).toBe('string');
+      }
+    });
+  });
+});

