import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import {
  parseAnalyticsQuery,
  getDashboardHandler,
  getMetricHandler,
  getOrderAnalyticsHandler,
  getUserAnalyticsHandler,
} from '../../src/routes/analytics.routes.js';
import type { AnalyticsQueryParams } from '../../src/routes/analytics.routes.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeOrder(overrides: Partial<Order> & { id: string }): Order {
  return {
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 100,
    status: 'pending',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: `${overrides.id}@example.com`,
    role: 'member',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

const validParams: AnalyticsQueryParams = {
  startDate: '2025-01-01',
  endDate: '2025-01-31',
  granularity: 'day',
};

// ---------------------------------------------------------------------------
// parseAnalyticsQuery
// ---------------------------------------------------------------------------

describe('parseAnalyticsQuery', () => {
  it('parses valid params', () => {
    const query = parseAnalyticsQuery(validParams);
    expect(query.timeRange.start).toEqual(new Date('2025-01-01'));
    expect(query.timeRange.end).toEqual(new Date('2025-01-31'));
    expect(query.granularity).toBe('day');
  });

  it('defaults granularity to day', () => {
    const query = parseAnalyticsQuery({ startDate: '2025-01-01', endDate: '2025-01-31' });
    expect(query.granularity).toBe('day');
  });

  it('throws on invalid startDate', () => {
    expect(() => parseAnalyticsQuery({ startDate: 'nope', endDate: '2025-01-31' }))
      .toThrow('Invalid startDate');
  });

  it('throws on invalid endDate', () => {
    expect(() => parseAnalyticsQuery({ startDate: '2025-01-01', endDate: 'nope' }))
      .toThrow('Invalid endDate');
  });

  it('throws when startDate >= endDate', () => {
    expect(() => parseAnalyticsQuery({ startDate: '2025-02-01', endDate: '2025-01-01' }))
      .toThrow('startDate must be before endDate');
  });

  it('throws on invalid granularity', () => {
    expect(() => parseAnalyticsQuery({ startDate: '2025-01-01', endDate: '2025-01-31', granularity: 'quarter' }))
      .toThrow('Invalid granularity');
  });
});

// ---------------------------------------------------------------------------
// Route handlers
// ---------------------------------------------------------------------------

describe('analytics route handlers', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // -- getDashboardHandler --------------------------------------------------

  describe('getDashboardHandler', () => {
    it('returns success with dashboard data', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1' }));

      const result = await getDashboardHandler(service, validParams);

      expect(result.success).toBe(true);
      expect(result.data.metrics).toHaveLength(4);
      expect(result.data.orders.totalOrders).toBe(1);
      expect(result.data.users.newUsers).toBe(1);
      expect(result.data.generatedAt).toBeInstanceOf(Date);
      expect(result.data.timeRange.start).toEqual(new Date('2025-01-01'));
    });

    it('returns success with empty data', async () => {
      const result = await getDashboardHandler(service, validParams);

      expect(result.success).toBe(true);
      expect(result.data.orders.totalOrders).toBe(0);
      expect(result.data.users.newUsers).toBe(0);
    });

